const form = document.querySelector('#profile-form');

form.addEventListener('submit', async (e) => {
  e.preventDefault();

  // Magically grabs all text inputs, checkboxes, AND files!
  const data = new FormData(form);

  // You can even add extra data manually
  data.append('timestamp', Date.now());

  // Send it directly to the server. 
  // Notice we DO NOT set headers! Fetch does it automatically for FormData.
  await fetch('/api/upload', {
    method: 'POST',
    body: data
  });
});
